10041	\begin{lemma}[The slice structure-sheaf ring map $\psi_r$]
10042	  \label{lem:slice_structureSheaf_hom}
10043	  \lean{AlgebraicGeometry.sliceStructureSheafHom,
10044	    AlgebraicGeometry.opensMapInvBase_isEquivalence,
10045	    AlgebraicGeometry.overPost_slice_isContinuous,
10046	    AlgebraicGeometry.sliceStructureSheafHom_pre_isRightAdjoint,
10047	    AlgebraicGeometry.sliceStructureSheafHom_isRightAdjoint}
10048	  \uses{lem:sheafPushforwardContinuous_mathlib, lem:scheme_hom_toRingCatSheafHom_mathlib,
10049	    lem:over_post_forget_mathlib, lem:pushforwardPushforwardEquivalence_mathlib,
10050	    lem:overEquivalence_isContinuous}
10051	  Let \(\varphi : X \cong Y\) be an isomorphism of schemes, \(U_i \subseteq X\) an (affine) open and
10052	  \(V_i = \varphi.\mathrm{inv}^{-1}\,U_i \subseteq Y\) its image. Let \(F : \operatorname{Opens} U_i \to
10053	  \operatorname{Opens} V_i\) be the continuous functor of opens-sites induced by the homeomorphism
10054	  underlying \(\varphi\) restricted to \(U_i\); since \(\varphi\) is an isomorphism, \(F\) is an
10055	  equivalence, so it is continuous (\(F.\operatorname{IsContinuous} J\,K\)) and final
10056	  (\(F.\operatorname{Final}\)). Let \(\mathcal{O}_{U_i} : \operatorname{Sheaf} J\,\operatorname{RingCat}\)
10057	  and \(\mathcal{O}_{V_i} : \operatorname{Sheaf} K\,\operatorname{RingCat}\) be the structure sheaves of
10058	  the two sliced opens-sites, regarded as sheaves of rings. Then there is a morphism of sheaves of rings
10059	  \[
10060	    \psi_r : \mathcal{O}_{U_i} \longrightarrow
10061	      \bigl(F.\operatorname{sheafPushforwardContinuous} \operatorname{RingCat} J\,K\bigr).\mathrm{obj}\,
10062	      \mathcal{O}_{V_i},
10063	  \]
10064	  carrying the instance \((\operatorname{SheafOfModules.pushforward}\psi_r).\operatorname{IsRightAdjoint}\)
10065	  — the right-adjointness obligation that makes the pullback functor along \(\psi_r\)
10066	  (Lemma~\ref{lem:sheafOfModules_pullback_mathlib}) available. This single cross-ring slice
10067	  structure-sheaf ring map is the datum from which the pullback functor of
10068	  Lemma~\ref{lem:pushforward_slice_pullback_iso} is built.
10069	\end{lemma}
10070	\begin{proof}
10071	  \uses{lem:scheme_hom_toRingCatSheafHom_mathlib, lem:over_post_forget_mathlib}
10072	  The functor \(F\) and the two structure sheaves \(\mathcal{O}_{U_i}\), \(\mathcal{O}_{V_i}\) arise by
10073	  restricting the scheme isomorphism \(\varphi\) to \(U_i\): the underlying homeomorphism restricts to a
10074	  homeomorphism \(U_i \cong V_i\), inducing the opens-site equivalence \(F\). The map \(\psi_r\) is the
10075	  structure-sheaf comparison of \(\varphi.\mathrm{hom}\) — its associated morphism of sheaves of rings
10076	  (Lemma~\ref{lem:scheme_hom_toRingCatSheafHom_mathlib}) — read along the opens-equivalence \(F\). The
10077	  transport to the sliced sites uses the Beck--Chevalley identity that post-composition with a functor
10078	  commutes with the forgetful functor out of the slice,
10079	  \(\operatorname{Over.post} F \circ \operatorname{Over.forget} = \operatorname{Over.forget} \circ F\)
10080	  (Lemma~\ref{lem:over_post_forget_mathlib}, an equality of functors holding by definition),
10081	  so the comparison descends to the over-categories with no further coherence datum. The
10082	  right-adjointness instance for \(\operatorname{SheafOfModules.pushforward}\psi_r\) holds because \(F\)
10083	  is an equivalence, whence its induced pushforward of sheaves of rings has a right adjoint. The result
10084	  is the slice structure-sheaf ring map \(\psi_r\).
10085	\end{proof}
